  fetcher: Fetcher,
  /**
   * Optional configuration object extending [`UseReverificationOptions`](https://clerk.com/docs/reference/hooks/use-reverification#use-reverification-options).
   */
  options?: Options,
) => UseReverificationResult<Fetcher>;

